package v1

import (
	"bytes"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"testing"
	"time"

	"github.com/stretchr/testify/require"
)

// SilenceInput is the structure for silence input in the bulk endpoint.
type SilenceInput struct {
	Matchers []SilenceMatcher `json:"matchers"`
	StartsAt time.Time        `json:"startsAt"`
	EndsAt   time.Time        `json:"endsAt"`
	Comment  string           `json:"comment"`
}

// SilenceMatcher represents a label matcher for a silence.
type SilenceMatcher struct {
	Name  string `json:"name"`
	Value string `json:"value"`
	IsRe  bool   `json:"isRe,omitempty"`
}

// SilenceOutput is the structure for silence output (created silence).
type SilenceOutput struct {
	ID string `json:"id"`
}

func TestBulkSilences_Success(t *testing.T) {
	api := &API{
		now:    time.Now,
		logger: nil,
	}

	// Test with a simple mock SilenceManager
	mockManager := &mockSilenceManager{
		silences: make(map[string]SilenceInput),
	}
	api.silenceManager = mockManager

	silences := []SilenceInput{
		{
			Matchers: []SilenceMatcher{
				{Name: "alertname", Value: "TestAlert", IsRe: false},
			},
			StartsAt: time.Now(),
			EndsAt:   time.Now().Add(1 * time.Hour),
			Comment:  "Test silence 1",
		},
		{
			Matchers: []SilenceMatcher{
				{Name: "job", Value: "prometheus", IsRe: false},
			},
			StartsAt: time.Now(),
			EndsAt:   time.Now().Add(2 * time.Hour),
			Comment:  "Test silence 2",
		},
	}

	body, err := json.Marshal(silences)
	require.NoError(t, err)

	req := httptest.NewRequest(http.MethodPost, "/api/v1/silences/bulk", bytes.NewReader(body))
	w := httptest.NewRecorder()

	result := api.silencesBulk(req)
	require.NoError(t, result.err, "expected no error, got %v", result.err)
	require.NotNil(t, result.data)

	// result.data should be a slice of SilenceOutput
	silenceIDs, ok := result.data.([]string)
	require.True(t, ok, "expected []string, got %T", result.data)
	require.Equal(t, 2, len(silenceIDs))
	require.NotEmpty(t, silenceIDs[0])
	require.NotEmpty(t, silenceIDs[1])
}

func TestBulkSilences_EmptyArray(t *testing.T) {
	api := &API{
		now:    time.Now,
		logger: nil,
	}

	mockManager := &mockSilenceManager{
		silences: make(map[string]SilenceInput),
	}
	api.silenceManager = mockManager

	silences := []SilenceInput{}

	body, err := json.Marshal(silences)
	require.NoError(t, err)

	req := httptest.NewRequest(http.MethodPost, "/api/v1/silences/bulk", bytes.NewReader(body))
	result := api.silencesBulk(req)

	// Empty array should be valid
	require.NoError(t, result.err)
	silenceIDs, ok := result.data.([]string)
	require.True(t, ok)
	require.Equal(t, 0, len(silenceIDs))
}

func TestBulkSilences_ValidationFailure(t *testing.T) {
	api := &API{
		now:    time.Now,
		logger: nil,
	}

	mockManager := &mockSilenceManager{
		silences: make(map[string]SilenceInput),
	}
	api.silenceManager = mockManager

	// Invalid silence - no matchers
	silences := []SilenceInput{
		{
			Matchers: []SilenceMatcher{},
			StartsAt: time.Now(),
			EndsAt:   time.Now().Add(1 * time.Hour),
			Comment:  "Invalid silence",
		},
	}

	body, err := json.Marshal(silences)
	require.NoError(t, err)

	req := httptest.NewRequest(http.MethodPost, "/api/v1/silences/bulk", bytes.NewReader(body))
	result := api.silencesBulk(req)

	// Should return error for validation failure
	require.NotNil(t, result.err)
}

func TestBulkSilences_InvalidJSON(t *testing.T) {
	api := &API{
		now:    time.Now,
		logger: nil,
	}

	mockManager := &mockSilenceManager{
		silences: make(map[string]SilenceInput),
	}
	api.silenceManager = mockManager

	// Invalid JSON
	req := httptest.NewRequest(http.MethodPost, "/api/v1/silences/bulk", bytes.NewReader([]byte("invalid json")))
	result := api.silencesBulk(req)

	require.NotNil(t, result.err)
}

func TestBulkSilences_InvalidTimeRange(t *testing.T) {
	api := &API{
		now:    time.Now,
		logger: nil,
	}

	mockManager := &mockSilenceManager{
		silences: make(map[string]SilenceInput),
	}
	api.silenceManager = mockManager

	// EndsAt before StartsAt
	silences := []SilenceInput{
		{
			Matchers: []SilenceMatcher{
				{Name: "alertname", Value: "TestAlert", IsRe: false},
			},
			StartsAt: time.Now().Add(2 * time.Hour),
			EndsAt:   time.Now(),
			Comment:  "Invalid time range",
		},
	}

	body, err := json.Marshal(silences)
	require.NoError(t, err)

	req := httptest.NewRequest(http.MethodPost, "/api/v1/silences/bulk", bytes.NewReader(body))
	result := api.silencesBulk(req)

	require.NotNil(t, result.err)
}

// mockSilenceManager is a mock implementation of SilenceManager for testing.
type mockSilenceManager struct {
	silences map[string]SilenceInput
	counter  int
}

// createSilence creates a silence and returns its ID.
func (m *mockSilenceManager) createSilence(s SilenceInput) (string, error) {
	if err := validateSilence(s); err != nil {
		return "", err
	}
	m.counter++
	id := generateSilenceID(m.counter)
	m.silences[id] = s
	return id, nil
}

// generateSilenceID generates a simple ID for testing purposes.
func generateSilenceID(counter int) string {
	return "silence-" + string(rune('a'+counter-1))
}

// validateSilence validates a silence input.
func validateSilence(s SilenceInput) error {
	if len(s.Matchers) == 0 {
		return NewErrorWithData("at least one matcher must be provided", nil)
	}
	if s.EndsAt.Before(s.StartsAt) {
		return NewErrorWithData("endsAt must be after startsAt", nil)
	}
	return nil
}

// NewErrorWithData creates a new error with data. This is a helper for testing.
// In the actual implementation, this would be an apiError.
func NewErrorWithData(msg string, data interface{}) error {
	return &apiError{errorBadData, nil}
}

