func TestBulkSilences_Success(t *testing.T) {
	api := &API{
		now:              time.Now,
		silenceManager:   &mockSilenceManager{silences: make(map[string]silenceInput)},
	}

	silences := []silenceInput{
		{
			Matchers: []silenceMatcher{
				{Name: "alertname", Value: "TestAlert", IsRe: false},
			},
			StartsAt: time.Now(),
			EndsAt:   time.Now().Add(1 * time.Hour),
			Comment:  "Test silence 1",
		},
		{
			Matchers: []silenceMatcher{
				{Name: "job", Value: "prometheus", IsRe: false},
			},
			StartsAt: time.Now(),
			EndsAt:   time.Now().Add(2 * time.Hour),
			Comment:  "Test silence 2",
		},
	}

	body, err := json.Marshal(silences)
	require.NoError(t, err)

	req := httptest.NewRequest(http.MethodPost, "/api/v1/silences/bulk", bytes.NewReader(body))
	result := api.silencesBulk(req)
	require.Nil(t, result.err, "expected no error, got %v", result.err)
	require.NotNil(t, result.data)

	// result.data should be a slice of strings
	silenceIDs, ok := result.data.([]string)
	require.True(t, ok, "expected []string, got %T", result.data)
	require.Equal(t, 2, len(silenceIDs))
	require.NotEmpty(t, silenceIDs[0])
	require.NotEmpty(t, silenceIDs[1])
}

